mapper.select:


    o.del_flag = '0'
           AND o.order_no like concat('%', #{orderNo}, '%')

        AND (
            o.wx_user_id = #{wxUserId}
            OR o.recipient_wx_user_id = #{wxUserId}
            OR (o.group_room_id is not null and exists(select 1 from kitchen_group_member gm where gm.room_id=o.group_room_id and gm.wx_user_id=#{wxUserId}))
            OR (o.couple_space_id is not null and exists(select 1 from kitchen_couple_space cs where cs.id=o.couple_space_id and (cs.user_a=#{wxUserId} or cs.user_b=#{wxUserId})))
        )

    AND o.service_type = #{serviceType}
    AND o.order_status = #{orderStatus}
        AND o.pay_status = #{payStatus}
    AND o.receiver_phone = #{receiverPhone}

        AND date_format(o.create_time,'%y%m%d') >= date_format(#{params.beginTime},'%y%m%d')


        AND date_format(o.create_time,'%y%m%d') <= date_format(#{params.endTime},'%y%m%d')


order by o.id desc

select count(1) from kitchen_order o where o.id=#{orderId} and o.del_flag='0' and (
    o.wx_user_id=#{userId} or o.recipient_wx_user_id=#{userId}
    or (o.group_room_id is not null and exists(select 1 from kitchen_group_member gm where gm.room_id=o.group_room_id and gm.wx_user_id=#{userId}))
    or (o.couple_space_id is not null and exists(select 1 from kitchen_couple_space cs where cs.id=o.couple_space_id and (cs.user_a=#{userId} or cs.user_b=#{userId})))
)

mapper.update:
update kitchen_order
order_status = #{orderStatus}, pay_status = #{payStatus}, chef_id = #{chefId}, receiver_name = #{receiverName}, receiver_phone = #{receiverPhone}, receiver_address = #{receiverAddress}, remark = #{remark}, update_by = #{updateBy}, update_time = sysdate()
where id = #{id}
